# These dicts reference "canonical names" only
# (i.e. the first name an object was registered with).
REGISTERED_NAMES_TO_OBJS = {}
REGISTERED_OBJS_TO_NAMES = {}


def register_internal_serializable(path, symbol):
    global REGISTERED_NAMES_TO_OBJS
    if isinstance(path, (list, tuple)):
        name = path[0]
    else:
        name = path
    REGISTERED_NAMES_TO_OBJS[name] = symbol
    REGISTERED_OBJS_TO_NAMES[symbol] = name


def get_symbol_from_name(name):
    return REGISTERED_NAMES_TO_OBJS.get(name, None)


def get_name_from_symbol(symbol):
    return REGISTERED_OBJS_TO_NAMES.get(symbol, None)


if namex:

    class keras_export(namex.export):
        def __init__(self, path):
            super().__init__(package="keras", path=path)

        def __call__(self, symbol):
            register_internal_serializable(self.path, symbol)
            return super().__call__(symbol)

else:

    class keras_export:
        def __init__(self, path):
            self.path = path

        def __call__(self, symbol):
            register_internal_serializable(self.path, symbol)
            return symbol

import weakref

from keras.src.backend.common import global_state


def _clear_tensor_attr(tensor_id, attr):
    attr_dict = global_state.get_global_attribute(f"{attr}_dict")
    if attr_dict is not None and tensor_id in attr_dict:
        del attr_dict[tensor_id]


def set_tensor_attr(tensor, attr, value):
    try:
        setattr(tensor, attr, value)
    except AttributeError:
        attr_dict = global_state.get_global_attribute(f"{attr}_dict")
        if attr_dict is None:
            if value is None:
                return
            attr_dict = {}
            global_state.set_global_attribute(f"{attr}_dict", attr_dict)
        if value is not None:
            attr_dict[id(tensor)] = value
            weakref.finalize(tensor, _clear_tensor_attr, id(tensor), attr)
        elif id(tensor) in attr_dict:
            del attr_dict[id(tensor)]


def get_tensor_attr(tensor, attr):
    if not hasattr(tensor, attr):
        attr_dict = global_state.get_global_attribute(f"{attr}_dict")
        if attr_dict is not None:
            return attr_dict.get(id(tensor), None)
        else:
            return None
    return getattr(tensor, attr, None)

from keras.src import backend
from keras.src import tree


def make_batch(values):
    from keras.src import ops

    if not values:
        raise ValueError("Cannot batch 0 values. Please file a bug.")

    with backend.device_scope("cpu"):
        return tree.map_structure(lambda *xs: ops.stack(xs), *values)


def make_string_batch(values):
    from keras.src import ops

    if not values:
        raise ValueError("Cannot batch 0 values. Please file a bug.")

    def batch_fn(*xs):
        if isinstance(xs[0], str):
            if backend.backend() == "tensorflow":
                import tensorflow as tf

                xs = [tf.convert_to_tensor(x, dtype=tf.string) for x in xs]
                xs = tf.stack(xs)
            return xs
        else:
            return ops.stack(xs)

    with backend.device_scope("cpu"):
        return tree.map_structure(batch_fn, *values)

